sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county ?sviRecord2000 ?svi2000 ?sviRecord2010 ?svi2010 ?sviRecord2022 ?svi2022 ?housingTransportationScore2022 ?populationChange2000To2022 ?povertyRate2022
WHERE {
  {
    SELECT ?county ?sviRecord2022 ?svi2022 ?housingTransportationScore2022 ?population2022 ?povertyRate2022
    WHERE {
      ?county a goo:County ;
              goo:locatedInState gokg:FloridaState .
      ?sviRecord2022 a goo:SVIRecord ;
                     goo:representsCounty ?county ;
                     goo:sviYear 2022 ;
                     goo:sviOverallScore ?svi2022 ;
                     goo:sviHousingTransportationTheme ?housingTransportationScore2022 ;
                     goo:totalPopulation ?population2022 ;
                     goo:povertyRate ?povertyRate2022 .
    }
    ORDER BY DESC(?housingTransportationScore2022)
    LIMIT 10
  }
  ?sviRecord2000 a goo:SVIRecord ;
                 goo:representsCounty ?county ;
                 goo:sviYear 2000 ;
                 goo:sviOverallScore ?svi2000 ;
                 goo:totalPopulation ?population2000 .
  ?sviRecord2010 a goo:SVIRecord ;
                 goo:representsCounty ?county ;
                 goo:sviYear 2010 ;
                 goo:sviOverallScore ?svi2010 .
  BIND((xsd:integer(?population2022) - xsd:integer(?population2000)) AS ?populationChange2000To2022)
}
ORDER BY DESC(?housingTransportationScore2022) ?county
